SELECT res_id AS resId, com_id AS comId, res_code AS resCode, res_name AS resName, res_type AS resType, quantity AS quantity, remark AS remark, created_at AS createdAt, updated_at AS updatedAt FROM resource WHERE com_id = #{comId}
AND (res_name LIKE CONCAT('%', #{keyword}, '%') OR res_code LIKE CONCAT('%', #{keyword}, '%'))
AND res_type = #{resType}
ORDER BY res_id DESC LIMIT #{startRow}, #{pageSize}

SELECT COUNT(*)
FROM resource
WHERE com_id = #{comId}

    AND (res_name LIKE CONCAT('%', #{keyword}, '%')
